29	//     drivers/iio/beamformer/adar1000.c  (adar1000_phase_values[])
30	// The 128 byte values themselves are factual data from the datasheet and are
31	// not subject to copyright; only the ADI driver code is GPL.
32	//
33	// Byte format (per datasheet):
34	//   bit  [7:6] reserved (0)
35	//   bit  [5]   polarity:  1 = positive lobe (sign(I) or sign(Q) >= 0)
36	//                          0 = negative lobe
37	//   bits [4:0] 5-bit unsigned magnitude (0..31)
38	// At magnitude=0 the polarity bit is physically meaningless; the datasheet
39	// uses POL=1 (e.g. VM_Q at 0 deg = 0x20, VM_I at 90 deg = 0x21).
40	//
41	// Index mapping is uniform: VM_I[k] / VM_Q[k] correspond to phase angle
42	// k * 360/128 = k * 2.8125 degrees.  Callers index as VM_*[phase % 128].
