100	bool ADAR1000Manager::powerUpSystem() {
101	    DIAG_SECTION("BF POWER-UP SEQUENCE");
102	    uint32_t t0 = HAL_GetTick();
103	    const uint8_t msg[] = "Starting System Power-Up Sequence...\r\n";
104	    HAL_UART_Transmit(&huart3, msg, sizeof(msg) - 1, 1000);
105	
106	    // Power-up sequence steps...
107	    DIAG("BF", "Enabling VDD_SW (3.3V)");
108	    HAL_GPIO_WritePin(EN_P_3V3_VDD_SW_GPIO_Port, EN_P_3V3_VDD_SW_Pin, GPIO_PIN_SET);
109	    HAL_Delay(2);
110	
111	    DIAG("BF", "Enabling VSS_SW (3.3V)");
112	    HAL_GPIO_WritePin(EN_P_3V3_SW_GPIO_Port, EN_P_3V3_SW_Pin, GPIO_PIN_SET);
113	    HAL_Delay(2);
114	
115	    // Initialize devices
116	    DIAG("BF", "Calling initializeAllDevices()");
117	    if (!initializeAllDevices()) {
118	        DIAG_ERR("BF", "initializeAllDevices() FAILED");
119	        const uint8_t err[] = "ERROR: ADAR1000 initialization failed!\r\n";
120	        HAL_UART_Transmit(&huart3, err, sizeof(err) - 1, 1000);
121	        return false;
122	    }
123	    DIAG("BF", "initializeAllDevices() OK");
124	
125	    // Start in RX mode
126	    DIAG("BF", "Setting initial mode to RX");
127	    switchToRXMode();
128	
129	    DIAG_ELAPSED("BF", "powerUpSystem() total", t0);
130	    const uint8_t success[] = "System Power-Up Sequence Completed Successfully.\r\n";
131	    HAL_UART_Transmit(&huart3, success, sizeof(success) - 1, 1000);
132	    return true;
133	}
