155	void ADAR1000Manager::switchToTXMode() {
156	    DIAG_SECTION("BF SWITCH TO TX MODE");
157	    DIAG("BF", "Step 1: LNA bias OFF");
158	    setLNABias(false);
159	    delayUs(10);
160	    DIAG("BF", "Step 2: Enable PA supplies");
161	    enablePASupplies();
162	    delayUs(100);
163	    DIAG("BF", "Step 3: PA bias ON");
164	    setPABias(true);
165	    delayUs(50);
166	    DIAG("BF", "Step 4: ADTR1107 -> TX");
167	    setADTR1107Control(true);
168	
169	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
170	        adarWrite(dev, REG_RX_ENABLES, 0x00, BROADCAST_OFF);
171	        adarWrite(dev, REG_TX_ENABLES, 0x0F, BROADCAST_OFF);
172	        adarSetTxBias(dev, BROADCAST_OFF);
173	        devices_[dev]->current_mode = BeamDirection::TX;
174	        DIAG("BF", "  dev[%u] TX enables=0x0F, TX bias set", dev);
175	    }
176	    current_mode_ = BeamDirection::TX;
177	    DIAG("BF", "switchToTXMode() complete");
178	}
