184	    delayUs(50);
185	    DIAG("BF", "Step 2: Disable PA supplies");
186	    disablePASupplies();
187	    delayUs(10);
188	    DIAG("BF", "Step 3: ADTR1107 -> RX");
189	    setADTR1107Control(false);
190	    DIAG("BF", "Step 4: Enable LNA supplies");
191	    enableLNASupplies();
192	    delayUs(50);
