242	bool ADAR1000Manager::setBeamAngle(float angle_degrees, BeamDirection direction) {
243	    DIAG("BF", "setBeamAngle(%.1f deg, %s)", (double)angle_degrees,
244	         direction == BeamDirection::TX ? "TX" : "RX");
245	    uint8_t phase_settings[4];
246	    calculatePhaseSettings(angle_degrees, phase_settings);
247	    DIAG("BF", "  phase[0..3] = %u, %u, %u, %u",
248	         phase_settings[0], phase_settings[1], phase_settings[2], phase_settings[3]);
249	
250	    if (direction == BeamDirection::TX) {
251	        setAllDevicesTXMode();
252	    } else {
253	        setAllDevicesRXMode();
254	    }
255	
256	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
257	        for (uint8_t ch = 0; ch < 4; ++ch) {
258	            if (direction == BeamDirection::TX) {
259	                adarSetTxPhase(dev, ch + 1, phase_settings[ch], BROADCAST_OFF);
260	                adarSetTxVgaGain(dev, ch + 1, kDefaultTxVgaGain, BROADCAST_OFF);
261	            } else {
262	                adarSetRxPhase(dev, ch + 1, phase_settings[ch], BROADCAST_OFF);
263	                adarSetRxVgaGain(dev, ch + 1, kDefaultRxVgaGain, BROADCAST_OFF);
264	            }
265	        }
266	    }
267	    return true;
268	}
