296	void ADAR1000Manager::updateBeamPosition() {
297	    if (!beam_sweeping_active_) return;
298	
299	    uint32_t current_time = HAL_GetTick();
300	    const std::vector<BeamConfig>& sequence =
301	        (current_mode_ == BeamDirection::TX) ? tx_beam_sequence_ : rx_beam_sequence_;
302	
303	    if (sequence.empty()) return;
304	
305	    if (current_time - last_beam_update_time_ >= beam_dwell_time_ms_) {
306	        const BeamConfig& beam = sequence[current_beam_index_];
307	        setCustomBeamPattern(beam.phase_settings, beam.gain_settings, current_mode_);
308	
309	        current_beam_index_ = (current_beam_index_ + 1) % sequence.size();
310	        last_beam_update_time_ = current_time;
311	    }
312	}
