331	float ADAR1000Manager::readTemperature(uint8_t deviceIndex) {
332	    if (deviceIndex >= devices_.size() || !devices_[deviceIndex]->initialized) {
333	        DIAG_WARN("BF", "readTemperature(dev[%u]) skipped: not initialized", deviceIndex);
334	        return -273.15f;
335	    }
