343	bool ADAR1000Manager::verifyDeviceCommunication(uint8_t deviceIndex) {
344	    if (deviceIndex >= devices_.size()) {
345	        DIAG_ERR("BF", "verifyDeviceComm(dev[%u]): index out of range", deviceIndex);
346	        return false;
347	    }
348	
349	    uint8_t test_value = 0xA5;
350	    adarWrite(deviceIndex, REG_SCRATCHPAD, test_value, BROADCAST_OFF);
351	    HAL_Delay(1);
352	    uint8_t readback = adarRead(deviceIndex, REG_SCRATCHPAD);
353	    bool pass = (readback == test_value);
354	    if (pass) {
355	        DIAG("BF", "verifyDeviceComm(dev[%u]): scratchpad 0xA5 -> 0x%02X OK", deviceIndex, readback);
356	    } else {
357	        DIAG_ERR("BF", "verifyDeviceComm(dev[%u]): scratchpad 0xA5 -> 0x%02X MISMATCH", deviceIndex, readback);
358	    }
359	    return pass;
360	}
