419	bool ADAR1000Manager::initializeSingleDevice(uint8_t deviceIndex) {
420	    if (deviceIndex >= devices_.size()) return false;
421	
422	    DIAG("BF", "  dev[%u] soft reset", deviceIndex);
423	    adarSoftReset(deviceIndex);
424	    HAL_Delay(10);
425	
426	    DIAG("BF", "  dev[%u] write ConfigA (SDO_ACTIVE)", deviceIndex);
427	    adarWriteConfigA(deviceIndex, INTERFACE_CONFIG_A_SDO_ACTIVE, BROADCAST_OFF);
428	    DIAG("BF", "  dev[%u] set RAM bypass (bias+beam)", deviceIndex);
429	    adarSetRamBypass(deviceIndex, BROADCAST_OFF);
430	
431	    // Initialize ADC
432	    DIAG("BF", "  dev[%u] enable ADC (2MHz clk)", deviceIndex);
433	    adarWrite(deviceIndex, REG_ADC_CONTROL, ADAR1000_ADC_2MHZ_CLK | ADAR1000_ADC_EN, BROADCAST_OFF);
434	
435	    // Verify communication with scratchpad test
436	    DIAG("BF", "  dev[%u] verifying SPI communication...", deviceIndex);
437	    bool comms_ok = verifyDeviceCommunication(deviceIndex);
438	    if (!comms_ok) {
439	        DIAG_WARN("BF", "  dev[%u] scratchpad verify FAILED but marking initialized anyway", deviceIndex);
440	    }
441	
442	    devices_[deviceIndex]->initialized = true;
443	    return true;
444	}
