446	bool ADAR1000Manager::initializeADTR1107Sequence() {
447	    DIAG_SECTION("ADTR1107 POWER SEQUENCE (9-step)");
448	    uint32_t t0 = HAL_GetTick();
449	
450		//Powering up ADTR1107 TX mode
451	    const uint8_t msg[] = "Starting ADTR1107 Power Sequence...\r\n";
452	    HAL_UART_Transmit(&huart3, msg, sizeof(msg) - 1, 1000);
453	
454	    // Step 1: Connect all GND pins to ground (assumed in hardware)
455	    DIAG("BF", "Step 1: GND pins (hardware -- assumed connected)");
456	
457	    // Step 2: Set VDD_SW to 3.3V
458	    DIAG("BF", "Step 2: VDD_SW -> 3.3V");
459	    HAL_GPIO_WritePin(EN_P_3V3_VDD_SW_GPIO_Port, EN_P_3V3_VDD_SW_Pin, GPIO_PIN_SET);
460	    HAL_Delay(1);
461	
462	    // Step 3: Set VSS_SW to -3.3V
463	    DIAG("BF", "Step 3: VSS_SW -> -3.3V");
464	    HAL_GPIO_WritePin(EN_P_3V3_SW_GPIO_Port, EN_P_3V3_SW_Pin, GPIO_PIN_SET);
465	    HAL_Delay(1);
466	
467	    // Step 4: Set CTRL_SW to RX mode initially via GPIO
468	    DIAG("BF", "Step 4: CTRL_SW -> RX (initial safe mode)");
469	    setADTR1107Control(false); // RX mode
470	    HAL_Delay(1);
471	
472	    // Step 5: Set VGG_LNA to 0
473	    DIAG("BF", "Step 5: VGG_LNA bias -> OFF (0x%02X)", kLnaBiasOff);
474	    uint8_t lna_bias_voltage = kLnaBiasOff;
475	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
476	        adarWrite(dev, REG_LNA_BIAS_ON, lna_bias_voltage, BROADCAST_OFF);
477	        adarWrite(dev, REG_LNA_BIAS_OFF, kLnaBiasOff, BROADCAST_OFF);
478	    }
479	
480	    // Step 6: Set VDD_LNA to 0V for TX mode
481	    DIAG("BF", "Step 6: VDD_LNA -> 0V (disable ADTR LNA supply)");
482	    HAL_GPIO_WritePin(EN_P_3V3_ADTR_GPIO_Port, EN_P_3V3_ADTR_Pin, GPIO_PIN_RESET);
483	    HAL_Delay(2);
484	
485	    // Step 7: Set VGG_PA to safe negative voltage (PA off for TX mode)
486	    /*A 0x00 value in the
487	    on or off bias registers, correspond to a 0 V output. A 0xFF in the
488	    on or off bias registers correspond to a −4.8 V output.*/
489	    DIAG("BF", "Step 7: VGG_PA -> safe bias 0x%02X (~ -1.75V, PA off)", kPaBiasTxSafe);
490	    uint8_t safe_pa_bias = kPaBiasTxSafe; // Safe negative voltage (-1.75V) to keep PA off
491	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
492	        adarWrite(dev, REG_PA_CH1_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
493	        adarWrite(dev, REG_PA_CH2_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
494	        adarWrite(dev, REG_PA_CH3_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
495	        adarWrite(dev, REG_PA_CH4_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
496	    }
497	    HAL_Delay(10);
498	
499	    // Step 8: Set VDD_PA to 0V (PA powered up for TX mode)
500	    DIAG("BF", "Step 8: Enable PA supplies (VDD_PA)");
501	    enablePASupplies();
502	    HAL_Delay(50);
503	
504	    // Step 9: Adjust VGG_PA voltage between −1.75 V and −0.25 V to achieve the desired IDQ_PA=220mA
505	    //Set VGG_PA to safe negative voltage (PA off for TX mode)
506	    /*A 0x00 value in the
507	    on or off bias registers, correspond to a 0 V output. A 0xFF in the
508	    on or off bias registers correspond to a −4.8 V output.*/
509	    DIAG("BF", "Step 9: VGG_PA -> Idq cal bias 0x%02X (~ -0.24V, target 220mA)", kPaBiasIdqCalibration);
510	    uint8_t Idq_pa_bias = kPaBiasIdqCalibration; // Safe negative voltage (-0.2447V) to keep PA off
511	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
512	        adarWrite(dev, REG_PA_CH1_BIAS_ON, Idq_pa_bias, BROADCAST_OFF);
513	        adarWrite(dev, REG_PA_CH2_BIAS_ON, Idq_pa_bias, BROADCAST_OFF);
514	        adarWrite(dev, REG_PA_CH3_BIAS_ON, Idq_pa_bias, BROADCAST_OFF);
515	        adarWrite(dev, REG_PA_CH4_BIAS_ON, Idq_pa_bias, BROADCAST_OFF);
516	    }
517	    HAL_Delay(10);
518	
519	    DIAG_ELAPSED("BF", "ADTR1107 power sequence", t0);
520	
521	    const uint8_t success[] = "ADTR1107 power sequence completed.\r\n";
522	    HAL_UART_Transmit(&huart3, success, sizeof(success) - 1, 1000);
523	
524	    return true;
525	}
