527	bool ADAR1000Manager::setAllDevicesTXMode() {
528	    DIAG("BF", "setAllDevicesTXMode(): ADTR1107 -> TX, then configure ADAR1000s");
529	    // Set ADTR1107 to TX mode first
530	    setADTR1107Mode(BeamDirection::TX);
531	
532	    // Then configure ADAR1000 for TX
533	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
534	        // Disable RX first
535	        adarWrite(dev, REG_RX_ENABLES, 0x00, BROADCAST_OFF);
536	
537	        // Enable TX channels and set bias
538	        adarWrite(dev, REG_TX_ENABLES, 0x0F, BROADCAST_OFF); // Enable all 4 channels
539	        adarSetTxBias(dev, BROADCAST_OFF);
540	
541	        devices_[dev]->current_mode = BeamDirection::TX;
542	        DIAG("BF", "  dev[%u] TX mode set (enables=0x0F, bias applied)", dev);
543	    }
544	    current_mode_ = BeamDirection::TX;
545	    return true;
546	}
