548	bool ADAR1000Manager::setAllDevicesRXMode() {
549	    DIAG("BF", "setAllDevicesRXMode(): ADTR1107 -> RX, then configure ADAR1000s");
550	    // Set ADTR1107 to RX mode first
551	    setADTR1107Mode(BeamDirection::RX);
552	
553	    // Then configure ADAR1000 for RX
554	    for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
555	        // Disable TX first
556	        adarWrite(dev, REG_TX_ENABLES, 0x00, BROADCAST_OFF);
557	
558	        // Enable RX channels
559	        adarWrite(dev, REG_RX_ENABLES, 0x0F, BROADCAST_OFF); // Enable all 4 channels
560	
561	        devices_[dev]->current_mode = BeamDirection::RX;
562	        DIAG("BF", "  dev[%u] RX mode set (enables=0x0F)", dev);
563	    }
564	    current_mode_ = BeamDirection::RX;
565	    return true;
566	}
