568	void ADAR1000Manager::setADTR1107Mode(BeamDirection direction) {
569	    if (direction == BeamDirection::TX) {
570	        DIAG_SECTION("ADTR1107 -> TX MODE");
571	        setADTR1107Control(true); // TX mode
572	
573	        // Step 1: Disable LNA power first
574	        DIAG("BF", "  Disable LNA supplies");
575	        disableLNASupplies();
576	        HAL_Delay(5);
577	
578	        // Step 2: Set LNA bias to safe off value
579	        DIAG("BF", "  LNA bias -> OFF (0x%02X)", kLnaBiasOff);
580	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
581	            adarWrite(dev, REG_LNA_BIAS_ON, kLnaBiasOff, BROADCAST_OFF); // Turn off LNA bias
582	        }
583	        HAL_Delay(5);
584	
585	        // Step 3: Enable PA power
586	        DIAG("BF", "  Enable PA supplies");
587	        enablePASupplies();
588	        HAL_Delay(10);
589	
590	        // Step 4: Set PA bias to operational value
591	        DIAG("BF", "  PA bias -> operational (0x%02X)", kPaBiasOperational);
592	        uint8_t operational_pa_bias = kPaBiasOperational; // Maximum bias for full power
593	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
594	            adarWrite(dev, REG_PA_CH1_BIAS_ON, operational_pa_bias, BROADCAST_OFF);
595	            adarWrite(dev, REG_PA_CH2_BIAS_ON, operational_pa_bias, BROADCAST_OFF);
596	            adarWrite(dev, REG_PA_CH3_BIAS_ON, operational_pa_bias, BROADCAST_OFF);
597	            adarWrite(dev, REG_PA_CH4_BIAS_ON, operational_pa_bias, BROADCAST_OFF);
598	        }
599	        HAL_Delay(5);
600	
601	        // Step 5: Set TR switch to TX mode
602	        DIAG("BF", "  TR switch -> TX (TR_SOURCE=1, BIAS_EN)");
603	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
604	            adarSetBit(dev, REG_SW_CONTROL, 2, BROADCAST_OFF); // TR_SOURCE = 1 (TX)
605	            adarSetBit(dev, REG_MISC_ENABLES, 5, BROADCAST_OFF); // BIAS_EN
606	        }
607	        DIAG("BF", "  ADTR1107 TX mode complete");
608	
609	    } else {
610	        // RECEIVE MODE: Enable LNA, Disable PA
611	        DIAG_SECTION("ADTR1107 -> RX MODE");
612	        setADTR1107Control(false); // RX mode
613	
614	        // Step 1: Disable PA power first
615	        DIAG("BF", "  Disable PA supplies");
616	        disablePASupplies();
617	        HAL_Delay(5);
618	
619	        // Step 2: Set PA bias to safe negative voltage
620	        DIAG("BF", "  PA bias -> safe (0x%02X)", kPaBiasRxSafe);
621	        uint8_t safe_pa_bias = kPaBiasRxSafe;
622	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
623	            adarWrite(dev, REG_PA_CH1_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
624	            adarWrite(dev, REG_PA_CH2_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
625	            adarWrite(dev, REG_PA_CH3_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
626	            adarWrite(dev, REG_PA_CH4_BIAS_ON, safe_pa_bias, BROADCAST_OFF);
627	        }
628	        HAL_Delay(5);
629	
630	        // Step 3: Enable LNA power
631	        DIAG("BF", "  Enable LNA supplies");
632	        enableLNASupplies();
633	        HAL_Delay(10);
634	
635	        // Step 4: Set LNA bias to operational value
636	        DIAG("BF", "  LNA bias -> operational (0x%02X)", kLnaBiasOperational);
637	        uint8_t operational_lna_bias = kLnaBiasOperational;
638	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
639	            adarWrite(dev, REG_LNA_BIAS_ON, operational_lna_bias, BROADCAST_OFF);
640	        }
641	        HAL_Delay(5);
642	
643	        // Step 5: Set TR switch to RX mode
644	        DIAG("BF", "  TR switch -> RX (TR_SOURCE=0, LNA_BIAS_OUT_EN)");
645	        for (uint8_t dev = 0; dev < devices_.size(); ++dev) {
646	            adarResetBit(dev, REG_SW_CONTROL, 2, BROADCAST_OFF); // TR_SOURCE = 0 (RX)
647	            adarSetBit(dev, REG_MISC_ENABLES, 4, BROADCAST_OFF); // LNA_BIAS_OUT_EN
648	        }
649	        DIAG("BF", "  ADTR1107 RX mode complete");
650	    }
651	}
