740	void ADAR1000Manager::calculatePhaseSettings(float angle_degrees, uint8_t phase_settings[4]) {
741	    const float freq = 10.5e9;
742	    const float c = 3e8;
743	    const float wavelength = c / freq;
744	    const float element_spacing = wavelength / 2;
745	
746	    float angle_rad = angle_degrees * M_PI / 180.0;
747	    float phase_shift = (2 * M_PI * element_spacing * sin(angle_rad)) / wavelength;
748	
749	    for (int i = 0; i < 4; ++i) {
750	        float element_phase = i * phase_shift;
751	        while (element_phase < 0) element_phase += 2 * M_PI;
752	        while (element_phase >= 2 * M_PI) element_phase -= 2 * M_PI;
753	        phase_settings[i] = static_cast<uint8_t>((element_phase / (2 * M_PI)) * 128);
754	    }
755	}
