774	uint32_t ADAR1000Manager::spiTransfer(uint8_t* txData, uint8_t* rxData, uint32_t size) {
775	    HAL_StatusTypeDef status;
776	
777	    if (rxData) {
778	        status = HAL_SPI_TransmitReceive(&hspi1, txData, rxData, size, 1000);
779	    } else {
