797	void ADAR1000Manager::adarWrite(uint8_t deviceIndex, uint32_t mem_addr, uint8_t data, uint8_t broadcast) {
798	    uint8_t instruction[3];
799	
800	    if (broadcast) {
801	        instruction[0] = 0x08;
802	    } else {
803	        instruction[0] = ((devices_[deviceIndex]->dev_addr & 0x03) << 5);
804	    }
805	
806	    instruction[0] |= (0x1F00 & mem_addr) >> 8;
807	    instruction[1] = (0xFF & mem_addr);
808	    instruction[2] = data;
809	
810	    setChipSelect(deviceIndex, true);
811	    spiTransfer(instruction, nullptr, sizeof(instruction));
812	    setChipSelect(deviceIndex, false);
813	}
