815	uint8_t ADAR1000Manager::adarRead(uint8_t deviceIndex, uint32_t mem_addr) {
816	    uint8_t instruction[3] = {0};
817	    uint8_t rx_buffer[3] = {0};
818	
819	    // Set SDO active
820	    adarWrite(deviceIndex, REG_INTERFACE_CONFIG_A, INTERFACE_CONFIG_A_SDO_ACTIVE, 0);
821	
822	    instruction[0] = 0x80 | ((devices_[deviceIndex]->dev_addr & 0x03) << 5);
823	    instruction[0] |= ((0xff00 & mem_addr) >> 8);
824	    instruction[1] = (0xff & mem_addr);
825	    instruction[2] = 0x00;
826	
827	    setChipSelect(deviceIndex, true);
828	    spiTransfer(instruction, rx_buffer, sizeof(instruction));
829	    setChipSelect(deviceIndex, false);
830	
831	    // Set SDO Inactive
832	    adarWrite(deviceIndex, REG_INTERFACE_CONFIG_A, 0, 0);
833	
834	    return rx_buffer[2];
835	}
