912	uint8_t ADAR1000Manager::adarAdcRead(uint8_t deviceIndex, uint8_t broadcast) {
913	    adarWrite(deviceIndex, REG_ADC_CONTROL, ADAR1000_ADC_ST_CONV, broadcast);
914	
915	    // Wait for conversion -- WARNING: no timeout, can hang if ADC never completes
916	    uint32_t t0 = HAL_GetTick();
917	    uint32_t polls = 0;
918	    while (!(adarRead(deviceIndex, REG_ADC_CONTROL) & 0x01)) {
919	        polls++;
920	        if (HAL_GetTick() - t0 > 100) {
921	            DIAG_ERR("BF", "adarAdcRead(dev[%u]): ADC conversion TIMEOUT after %lu ms, %lu polls",
922	                     deviceIndex, (unsigned long)(HAL_GetTick() - t0), (unsigned long)polls);
923	            return 0;
924	        }
925	    }
926	    DIAG("BF", "adarAdcRead(dev[%u]): conversion done in %lu ms (%lu polls)",
927	         deviceIndex, (unsigned long)(HAL_GetTick() - t0), (unsigned long)polls);
928	
929	    return adarRead(deviceIndex, REG_ADC_OUT);
930	}
