        enableLNASupplies();
        setPABias(true);
        setLNABias(true);
    } else {
        switch_settling_time_us_ = 50;
        DIAG("BF", "  settling time = 50 us");
    }
}

void ADAR1000Manager::setBeamDwellTime(uint32_t ms) {
