1960		                        channel, DAC_val, Idq_reading[channel+8]);
1961		              break;
1962		          }
1963		          DAC_val = DAC_val - 4;
1964		          DAC5578_WriteAndUpdateChannelValue(&hdac2, channel, DAC_val);
1965		          adc2_readings[channel] = ADS7830_Measure_SingleEnded(&hadc2, channel); // B13 fix: was adc1_readings
1966		          Idq_reading[channel+8] = (3.3/255) * adc2_readings[channel] / (50 * 0.005);
1967		      } while (DAC_val > 38 && abs(Idq_reading[channel+8] - 1.680) > 0.2); // B12 fix: loop while FAR from target
1968		      DIAG("PA", "  DAC2 ch%d calibrated: DAC_val=%d Idq=%.3fA iters=%d",
1969		           channel, DAC_val, Idq_reading[channel+8], safety_counter);
1970		  }
1971		  DIAG("PA", "PA IDQ calibration sequence COMPLETE");
1972	  }
