5	/**
6	  * @brief  Initialize the DAC5578
7	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
8	  * @param  hi2c: pointer to an I2C_HandleTypeDef structure
9	  * @param  i2c_addr: I2C address of the DAC
10	  * @param  resolution: DAC resolution (only 8 is valid for DAC5578)
11	  * @param  ldac_port: GPIO port for LDAC pin
12	  * @param  ldac_pin: GPIO pin for LDAC pin
13	  * @param  clr_port: GPIO port for CLR pin
14	  * @param  clr_pin: GPIO pin for CLR pin
15	  * @retval bool: true if successful, false otherwise
16	  */
17	bool DAC5578_Init(DAC5578_HandleTypeDef *hdac, I2C_HandleTypeDef *hi2c, uint8_t i2c_addr, 
18	                  uint8_t resolution, GPIO_TypeDef *ldac_port, uint16_t ldac_pin,
19	                  GPIO_TypeDef *clr_port, uint16_t clr_pin) {
20	    
21	    DIAG("PA", "DAC5578_Init: addr=0x%02X (shifted=0x%02X), res=%u", i2c_addr, i2c_addr << 1, resolution);
22	    
23	    if (hdac == NULL || hi2c == NULL) {
24	        DIAG_ERR("PA", "DAC5578_Init: NULL handle(s)");
25	        return false;
26	    }
27	    
28	    /* DAC5578 is 8-bit only */
29	    hdac->resolution_bits = 8;
30	    hdac->clear_code = DAC5578_CLR_CODE_ZERO; // Default clear to zero
31	    
32	    hdac->hi2c = hi2c;
33	    hdac->i2c_addr = i2c_addr << 1; // HAL requires 7-bit address shifted left
34	    hdac->ldac_port = ldac_port;
35	    hdac->ldac_pin = ldac_pin;
36	    hdac->clr_port = clr_port;
37	    hdac->clr_pin = clr_pin;
38	    
39	    /* Set LDAC high (inactive) and CLR high (normal operation) */
40	    if (ldac_port != NULL) {
41	        DIAG("PA", "  LDAC pin -> HIGH (inactive)");
42	        HAL_GPIO_WritePin(ldac_port, ldac_pin, GPIO_PIN_SET);
43	    }
44	    
45	    if (clr_port != NULL) {
46	        DIAG("PA", "  CLR pin -> HIGH (normal operation)");
47	        HAL_GPIO_WritePin(clr_port, clr_pin, GPIO_PIN_SET);
48	    }
49	
50	    /* Reset the DAC and enable internal reference by default */
51	    DIAG("PA", "  Resetting DAC5578...");
52	    bool success = DAC5578_Reset(hdac);
53	    if (success) {
54	        DIAG("PA", "  Enabling internal reference...");
55	        success = DAC5578_SetInternalReference(hdac, true);
56	    } else {
57	        DIAG_ERR("PA", "  DAC5578_Reset FAILED");
58	    }
59	
60	    /* Set the clear code in the device */
61	    if (success) {
62	        DIAG("PA", "  Setting clear code to ZERO...");
63	        success = DAC5578_SetClearCode(hdac, hdac->clear_code);
64	    }
65	
66	    DIAG("PA", "DAC5578_Init: %s", success ? "OK" : "FAILED");
67	    return success;
68	}
