70	/**
71	  * @brief  Reset the DAC5578
72	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
73	  * @retval bool: true if successful, false otherwise
74	  */
75	bool DAC5578_Reset(DAC5578_HandleTypeDef *hdac) {
76	    DIAG("PA", "DAC5578_Reset: addr=0x%02X", hdac->i2c_addr);
77	    uint8_t buffer[3];
78	    buffer[0] = DAC5578_CMD_RESET;
79	    buffer[1] = 0x00;
80	    buffer[2] = 0x00;
81	
82	    HAL_StatusTypeDef status = HAL_I2C_Master_Transmit(hdac->hi2c, hdac->i2c_addr, buffer, 3, HAL_MAX_DELAY);
83	    if (status != HAL_OK) {
84	        DIAG_ERR("PA", "DAC5578_Reset: I2C transmit FAILED, HAL status=%d", (int)status);
85	    }
86	    return (status == HAL_OK);
87	}
