89	/**
90	  * @brief  Write a value to a specific channel's input register
91	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
92	  * @param  channel: DAC channel (0-7)
93	  * @param  value: 8-bit value to write
94	  * @retval bool: true if successful, false otherwise
95	  */
96	bool DAC5578_WriteChannelValue(DAC5578_HandleTypeDef *hdac, uint8_t channel, uint16_t value) {
97	    if (channel > 7) {
98	        return false;
99	    }
100	
101	    /* DAC5578 is 8-bit, so mask value */
102	    value &= 0xFF;
103	
104	    return DAC5578_CommandWrite(hdac, DAC5578_CMD_WRITE | (channel & 0x7), value);
105	}
106	
107	/**
108	  * @brief  Update a specific channel's DAC register from input register
109	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
110	  * @param  channel: DAC channel (0-7) or DAC5578_CHANNEL_BROADCAST
111	  * @retval bool: true if successful, false otherwise
112	  */
113	bool DAC5578_UpdateChannel(DAC5578_HandleTypeDef *hdac, uint8_t channel) {
114	    if (channel > 7 && channel != DAC5578_CHANNEL_BROADCAST) {
115	        return false;
116	    }
117	
118	    /* Update command with channel selection */
119	    uint8_t command = DAC5578_CMD_UPDATE | (channel & 0x7);
120	    if (channel == DAC5578_CHANNEL_BROADCAST) {
121	        command = DAC5578_CMD_UPDATE | 0x8; // Broadcast flag
122	    }
123	
124	    uint8_t buffer[3];
125	    buffer[0] = command;
126	    buffer[1] = 0x00;
127	    buffer[2] = 0x00;
128	
129	    HAL_StatusTypeDef status = HAL_I2C_Master_Transmit(hdac->hi2c, hdac->i2c_addr, buffer, 3, HAL_MAX_DELAY);
130	    return (status == HAL_OK);
131	}
