133	/**
134	  * @brief  Write and update a specific channel in one operation
135	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
136	  * @param  channel: DAC channel (0-7)
137	  * @param  value: 8-bit value to write and update
138	  * @retval bool: true if successful, false otherwise
139	  */
140	bool DAC5578_WriteAndUpdateChannelValue(DAC5578_HandleTypeDef *hdac, uint8_t channel, uint16_t value) {
141	    if (channel > 7) {
142	        DIAG_ERR("PA", "DAC5578_WriteAndUpdate: channel %u out of range", channel);
143	        return false;
144	    }
145	
146	    /* DAC5578 is 8-bit, so mask value */
147	    value &= 0xFF;
148	
149	    DIAG("PA", "DAC5578_WriteAndUpdate: addr=0x%02X ch=%u val=0x%02X (%u)", hdac->i2c_addr, channel, value, value);
150	    return DAC5578_CommandWrite(hdac, DAC5578_CMD_WRITE_UPDATE | (channel & 0x7), value);
151	}
