153	/**
154	  * @brief  Write the same value to all channels' input registers
155	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
156	  * @param  value: 8-bit value to write to all channels
157	  * @retval bool: true if successful, false otherwise
158	  */
159	bool DAC5578_WriteAllChannels(DAC5578_HandleTypeDef *hdac, uint16_t value) {
160	    /* DAC5578 is 8-bit, so mask value */
161	    value &= 0xFF;
162	
163	    return DAC5578_CommandWrite(hdac, DAC5578_CMD_WRITE_ALL, value);
164	}
