166	/**
167	  * @brief  Read the input register value of a specific channel
168	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
169	  * @param  channel: DAC channel (0-7)
170	  * @param  value: pointer to store the read value
171	  * @retval bool: true if successful, false otherwise
172	  */
173	bool DAC5578_ReadInputChannelValue(DAC5578_HandleTypeDef *hdac, uint8_t channel, uint16_t *value) {
174	    if (channel > 7) {
175	        return false;
176	    }
177	
178	    /* Note: DAC5578 has limited read capability - this reads back the input register */
179	    return DAC5578_CommandRead(hdac, DAC5578_CMD_WRITE | (channel & 0x7), value);
