182	/**
183	  * @brief  Read the DAC register value (current output) of a specific channel
184	  * @param  hdac: pointer to a DAC5578_HandleTypeDef structure
185	  * @param  channel: DAC channel (0-7)
186	  * @param  value: pointer to store the read value
187	  * @retval bool: true if successful, false otherwise
188	  */
189	bool DAC5578_ReadDACChannelValue(DAC5578_HandleTypeDef *hdac, uint8_t channel, uint16_t *value) {
190	    if (channel > 7) {
191	        return false;
192	    }
193	
194	    /* Note: DAC5578 has limited read capability - this reads back the DAC register */
195	    return DAC5578_CommandRead(hdac, DAC5578_CMD_UPDATE | (channel & 0x7), value);
