387	    uint8_t buffer[3];
388	    buffer[0] = command;
389	    buffer[1] = (value >> 8) & 0xFF; // MSB (should be 0 for 8-bit DAC)
390	    buffer[2] = value & 0xFF;        // LSB (actual 8-bit data)
391	
392	    HAL_StatusTypeDef status = HAL_I2C_Master_Transmit(hdac->hi2c, hdac->i2c_addr, buffer, 3, HAL_MAX_DELAY);
393	    if (status != HAL_OK) {
