404	  * @retval bool: true if successful, false otherwise
405	  */
406	bool DAC5578_CommandRead(DAC5578_HandleTypeDef *hdac, uint8_t command, uint16_t *value) {
407	    uint8_t buffer[3];
408	
409	    /* First write the command to set up readback */
410	    HAL_StatusTypeDef status = HAL_I2C_Master_Transmit(hdac->hi2c, hdac->i2c_addr, &command, 1, HAL_MAX_DELAY);
411	    if (status != HAL_OK) {
412	        DIAG_ERR("PA", "DAC5578 I2C read setup FAILED: addr=0x%02X cmd=0x%02X HAL=%d", hdac->i2c_addr, command, (int)status);
413	        return false;
414	    }
415	
416	    /* Then read 3 bytes back */
417	    status = HAL_I2C_Master_Receive(hdac->hi2c, hdac->i2c_addr, buffer, 3, HAL_MAX_DELAY);
418	    if (status != HAL_OK) {
419	        DIAG_ERR("PA", "DAC5578 I2C read data FAILED: addr=0x%02X cmd=0x%02X HAL=%d", hdac->i2c_addr, command, (int)status);
420	        return false;
421	    }
422	
423	    /* Extract the 8-bit value from the response */
424	    *value = buffer[2] & 0xFF;
425	    DIAG("PA", "DAC5578_Read: addr=0x%02X cmd=0x%02X => 0x%02X", hdac->i2c_addr, command, *value);
426	    return true;
427	}
